def count_pairs(n, l, r, a):
    a.sort()
    left, right = 0, 0
    count = 0
    while right < n:
        while right < n and a[right] + a[left] <= r:
            right += 1
        while left < right and a[right] - a[left] >= l:
            left += 1
        count += right - left
    return count

