    if (N * (N + 1)) // 2 != E + O:
        return False

    # Check if we can have exactly E even-sum subarrays
    # For a subarray to have an even sum, the number of odd numbers in it must be even
    # If we use a pattern like even, odd, even, odd, ..., we can ensure E even-sum subarrays
    # The maximum number of even-sum subarrays we can have is N/2 (if N is even) or (N-1)/2 + 1 (if N is odd)

    # Check if N is even
    if N % 2 == 0:
        if E > N // 2:
            return False
    else:
        if E > (N - 1) // 2:
            return False

    return True

