from collections import defaultdict

def count_trust_lines(N, B, queries):
    # Initialize the graph where each chef points to the next n_i chefs
    graph = defaultdict(list)

    # Read the number of chefs and their trusted chefs
    for i in range(1, N + 1):
        n_i = int(input().strip())
        for _ in range(n_i):
            j = int(input().strip()) + i
            if j <= N:
                graph[i].append(j)

    # Precompute the number of ways to reach each chef from B
    # dp[i][j] represents the number of ways to reach chef i from chef j
    dp = [[0] * (N + 1) for _ in range(N + 1)]

    # Base case: there's exactly one way to reach a chef from itself
    for i in range(1, N + 1):
        dp[i][i] = 1

    # Fill the DP table
    for i in range(1, N + 1):
        for j in graph[i]:
            dp[j][i] = 1

    for k in range(1, N + 1):
        for i in range(1, N + 1):
            for j in range(1, N + 1):
                if dp[j][i] and dp[k][j]:
                    dp[i][k] += dp[j][i]
                    dp[i][k] %= 1000000007

    # Answer the queries
    results = []
    for query in queries:
        results.append(dp[B][query])

    return results

