def game_winner(N):
    # Base case: if N is 0, it's Bob's turn and he wins
    if N == 0:
        return "Bob"

    # If N is 1, it's Alice's turn and she wins
    if N == 1:
        return "Alice"

    # Check if N is a power of 2
    if (N & (N - 1)) == 0:
        return "Alice"

    # If N is even, Alice can always divide it by 2
    if N % 2 == 0:
        return "Alice"

    # If N is odd, Bob can always subtract 1
    return "Bob"

