def count_ways_to_split(arr):
    n = len(arr)
    total_sum = sum(arr)

    # Check if the total sum is divisible by 3
    if total_sum % 3 != 0:
        return 0

    target_sum = total_sum // 3
    prefix_sums = [0] * (n + 1)

    # Calculate prefix sums
    for i in range(1, n + 1):
        prefix_sums[i] = prefix_sums[i - 1] + arr[i - 1]

    count = 0

    # Iterate through the array to find split points
    for i in range(1, n - 1):
        if prefix_sums[i] == target_sum:
            for j in range(i + 1, n):
                if prefix_sums[j] - prefix_sums[i] == target_sum:
                    if prefix_sums[n] - prefix_sums[j] == target_sum:
                        count += 1

    return count

