def min_operations_to_make_odd(tokens):
    count_fusions = 0
    count_reductions = 0

    for token in tokens:
        if token % 2 == 0:
            # Reduce the token to an odd number
            while token % 2 == 0:
                token //= 2
                count_reductions += 1

            # Add the token back to the list as an odd number
            tokens.append(token)

    return count_fusions + count_reductions

