def can_reach_final_state(n, m, k, doors, initial_positions, final_positions):
    # Initialize a dictionary to map each room to its connected rooms
    adjacency_list = defaultdict(list)
    for door in doors:
        u, v = door
        adjacency_list[u].append(v)
        adjacency_list[v].append(u)

    # Initialize a dictionary to map each resident to their keys and their current position
    residents = {}
    for i in range(k):
        name, room, num_keys = initial_positions[i].split()
        residents[name] = {'room': int(room), 'keys': set(map(int, initial_positions[i+1].split()[1:])), 'connected_rooms': set(adjacency_list[int(room)])}

    # Function to simulate opening and closing doors
    def open_door(room, resident):
        if room in residents[resident]['connected_rooms']:
            residents[resident]['connected_rooms'].remove(room)
        else:
            residents[resident]['connected_rooms'].add(room)

    # Function to simulate key sharing
    def share_key(resident1, resident2):
        if resident1 in residents and resident2 in residents:
            residents[resident1]['keys'].update(residents[resident2]['keys'])
            residents[resident2]['keys'].update(residents[resident1]['keys'])

    # Simulate the first night
    for _ in range(2):  # Two nights, Thursday and Friday
        for resident, data in residents.items():
            for key in data['keys']:
                open_door(key, resident)
            share_key(resident, resident)  # Residents can share keys with themselves

    # Simulate the second night
    for _ in range(2):  # Two nights, Thursday and Friday
        for resident, data in residents.items():
            for key in data['keys']:
                open_door(key, resident)
            share_key(resident, resident)  # Residents can share keys with themselves

    # Check if the final positions match the second night's configuration
    return residents == {name: {'room': int(room), 'keys': set(map(int, final_positions[i+1].split()[1:])), 'connected_rooms': set(adjacency_list[int(room)])} for i in range(k)}

