from collections import defaultdict, deque

def bfs(initial_state, target_state, adjacency_list):
    queue = deque([initial_state])
    visited = set([initial_state])

    while queue:
        current_state = queue.popleft()

        # Check if we reached the target state
        if current_state == target_state:
            return True

        # Try all possible door operations
        open_doors, residents = current_state
        for i, (door, can_open) in enumerate(adjacency_list):
            if can_open and door not in open_doors:
                new_open_doors = open_doors | {door}
                new_residents = []
                for resident, (room, keys) in enumerate(residents):
                    if room in open_doors:
                        new_residents.append((resident, room, keys))
                    else:
                        new_residents.append((resident, room, [k for k in keys if k not in open_doors]))
                new_state = (new_open_doors, tuple(new_residents))
                if new_state not in visited:
                    visited.add(new_state)
                    queue.append(new_state)

    return False

