from collections import defaultdict, deque

def bfs(graph, start):
    visited = set()
    queue = deque([(start, 0)])
    while queue:
        node, steps = queue.popleft()
        if node in visited:
            continue
        visited.add(node)
        for neighbor in graph[node]:
            if neighbor not in visited:
                queue.append((neighbor, steps + 1))
    return visited

