def parse_expression(line: str) -> (str, str, str):
    parts = line.split()
    var_name = parts[0]
    op = parts[1]
    left = parts[2]
    right = parts[3] if len(parts) > 3 else '?'
    return var_name, op, left, right

def build_graph(variables: List[str], expressions: List[str]) -> defaultdict:
    graph = defaultdict(list)
    for var in variables:
        graph[var].append(var)
    for expr in expressions:
        name, op, left, right = parse_expression(expr)
        if left != '?':
            graph[left].append(name)
        if right != '?':
            graph[right].append(name)
    return graph

def dfs(node: str, graph: defaultdict, visited: set, min_val: int, max_val: int) -> None:
    visited.add(node)
    if node in var_values:
        min_val = min(min_val, var_values[node])
        max_val = max(max_val, var_values[node])
    else:
        for child in graph[node]:
            dfs(child, graph, visited, min_val, max_val)
        if node == 'a' and '?' in var_values:
            min_val = min(min_val, var_values['a'])
            max_val = max(max_val, var_values['a'])
    return

def calculate_values(graph: defaultdict, expressions: List[str]) -> None:
    for expr in expressions:
        name, op, left, right = parse_expression(expr)
        if left == '?' and right == '?':
            var_values[name] = 0
        elif left == '?' and right != '?':
            var_values[name] = eval(f'{right} {op} 0')
        elif left != '?' and right == '?':
            var_values[name] = eval(f'{left} {op} 0')
        else:
            var_values[name] = eval(f'{left} {op} {right}')
    return

