def parse_input():
    n, m = map(int, input().split())
    variables = {}
    for _ in range(n):
        name, op = input().split(':=')
        if op == '0' or op == '1':  # Binary number
            variables[name] = int(op, 2)
        else:
            operands = op.split()
            if operands[0] == '?' or operands[2] == '?':
                variables[name] = -1  # Placeholder for unknown operands
            else:
                variables[name] = op
    return n, m, variables

def build_graph(variables):
    graph = defaultdict(list)
    for name, op in variables.items():
        if isinstance(op, str):
            op1, op2 = op.split()
            if op1 != '?':
                graph[op1].append((name, op))
            if op2 != '?':
                graph[op2].append((name, op))
    return graph

def topological_sort(graph):
    in_degree = {node: 0 for node in graph}
    for node in graph:
        for neighbor, _ in graph[node]:
            in_degree[neighbor] += 1

    queue = deque([node for node in in_degree if in_degree[node] == 0])
    topo_order = []

    while queue:
        node = queue.popleft()
        topo_order.append(node)
        for neighbor, _ in graph[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    return topo_order

def min_max_scores(n, m, variables, graph):
    min_scores = [float('inf')] * n
    max_scores = [-float('inf')] * n
    topo_order = topological_sort(graph)

    for node in topo_order:
        if variables[node] == -1:
            continue

        if isinstance(variables[node], int):
            min_scores[nodes.index(node)] = variables[node]
            max_scores[nodes.index(node)] = variables[node]
            continue

        op1, op2 = variables[node].split()
        if op1 != '?' and op2 != '?':
            min_score = min(min_scores[nodes.index(op1)], min_scores[nodes.index(op2)])
            max_score = max(max_scores[nodes.index(op1)], max_scores[nodes.index(op2)])
