            max_score = max(max_scores[nodes.index(op2)], op2)
        elif op2 == '?':
            min_score = min(min_scores[nodes.index(op1)], op1)
            max_score = max(max_scores[nodes.index(op1)], op1)

        min_scores[nodes.index(node)] = min_score
        max_scores[nodes.index(node)] = max_score

    min_value = min(min_scores)
