    def evaluate_expression(value, operation, other_value=None):
        if operation == 'AND':
            return int(value, 2) & int(other_value, 2)
        elif operation == 'OR':
            return int(value, 2) | int(other_value, 2)
        elif operation == 'XOR':
            return int(value, 2) ^ int(other_value, 2)

    # Initialize DP tables
    min_values = {var: float('inf') for var in variables}
    max_values = {var: float('-inf') for var in variables}

    # Fill the DP tables
    for bit_value in range(1 << m):
        for var, (value, operation) in variables.items():
            if value is not None:
                min_values[var] = min(min_values[var], int(value, 2))
                max_values[var] = max(max_values[var], int(value, 2))
            else:
                if operation == 'AND':
                    min_values[var] = min(min_values[var], evaluate_expression(var, 'AND', bin(bit_value)[2:].zfill(m)))
                    max_values[var] = max(max_values[var], evaluate_expression(var, 'AND', bin(bit_value)[2:].zfill(m)))
                elif operation == 'OR':
