                    min_values[var] = min(min_values[var], evaluate_expression(var, 'XOR', bin(bit_value)[2:].zfill(m)))
                    max_values[var] = max(max_values[var], evaluate_expression(var, 'XOR', bin(bit_value)[2:].zfill(m)))

    # Determine the minimum and maximum values for Peter's choice
    min_peter_choice = ''.join(format(min_values[var] % (1 << m), '0' + str(m)) for var in variables)
