def dfs(graph, visited, node, weight_limit, beauty, max_beauty):
    visited[node] = True
    current_weight = weight_limit
    current_beauty = beauty

    for neighbor in graph[node]:
        if not visited[neighbor]:
            new_weight = current_weight - weight_limit
            new_beauty = current_beauty + beauty

            if new_weight >= 0:
                max_beauty = max(max_beauty, dfs(graph, visited, neighbor, new_weight, new_beauty, max_beauty))

    return max_beauty

