from collections import defaultdict

def max_beauty(n, m, w, weights, beauties, friendships):
    # Create the adjacency list for the graph
    graph = defaultdict(list)
    for x, y in friendships:
        graph[x].append(y)
        graph[y].append(x)

    # Initialize the DP table
    dp = [[[-float('inf')] * (w + 1) for _ in range(n + 1)] for _ in range(n + 1)]

    # Base case: no Hoses in any group
    for i in range(n + 1):
        dp[0][i][0] = 0

    # Fill the DP table
    for i in range(1, n + 1):
        for j in range(i + 1, n + 1):
            for k in range(w + 1):
                # Case 1: Do not include any Hoses from group (i, j)
                dp[i][j][k] = dp[i - 1][j - 1][k]
                # Case 2: Include all Hoses from group (i, j)
                if k >= weights[i - 1] + weights[j - 1]:
                    dp[i][j][k] = max(dp[i][j][k], beauties[i - 1] + beauties[j - 1] + dp[i - 1][0][k - (weights[i - 1] + weights[j - 1])])
                # Case 3: Include exactly one Hose from group (i, j)
                for l in range(1, i):
                    if k >= weights[l - 1] + weights[j - 1]:
                        dp[i][j][k] = max(dp[i][j][k], dp[l - 1][j - 1][k - (weights[l - 1] + weights[j - 1])] + beauties[i - 1])
                for l in range(1, j):
                    if k >= weights[i - 1] + weights[l - 1]:
                        dp[i][j][k] = max(dp[i][j][k], dp[i - 1][l - 1][k - (weights[i - 1] + weights[l - 1])] + beauties[j - 1])

    # Find the maximum beauty for total weight <= w
    max_beauty = 0
    for i in range(1, n + 1):
        for j in range(1, n + 1):
            for k in range(w + 1):
                if dp[i][j][k] != -float('inf'):
                    max_beauty = max(max_beauty, dp[i][j][k])

    return max_beauty

