def simulate_balls(n, m, k, grid, drops):
    # Initialize the direction array
    directions = [0] * (m + 1)

    # Process each ball's drop
    for i in range(k):
        col = drops[i]
        current_col = col

        # Simulate the ball's movement
        for _ in range(n):
            if current_col == 1:
                # Move right
                if directions[current_col] == 0:
                    current_col += 1
                else:
                    break
            elif current_col == m:
                # Move left
                if directions[current_col] == 1:
                    current_col -= 1
                else:
                    break
            else:
                # Move down
                if directions[current_col] == 2:
                    current_col += 1
                else:
                    break

        # Update the grid
        for j in range(n):
            grid[j][current_col] = 2

    # Collect the final positions of the balls
    final_positions = []
    for col in range(1, m + 1):
        if grid[-1][col] != 2:
            final_positions.append(col)

    return final_positions

