from collections import defaultdict

def prime_factors(n):
    """Return the prime factors of a number."""
    factors = defaultdict(int)
    # Check for number of 2s that divide n
    while n % 2 == 0:
        factors[2] += 1
        n //= 2
    # n must be odd at this point, so we can skip one element (Note i = i +2)
    for i in range(3, int(n**0.5) + 1, 2):
        # While i divides n, add i and divide n
        while n % i == 0:
            factors[i] += 1
            n //= i
    # This condition is to check if n is a prime number greater than 2
    if n > 2:
        factors[n] += 1
    return factors

def gcd_of_subset(sequence):
    """Return the size of the smallest subset with gcd 1."""
    # Dictionary to store prime factors of each number
    prime_factors_dict = {num: prime_factors(num) for num in sequence}

    # Set to keep track of numbers that have been added to the subset
    added_numbers = set()

    # Iterate through the sequence to build the subset
    for num in sequence:
        # Check if adding this number to the subset would maintain gcd 1
        can_add = True
        for prime in prime_factors_dict[num]:
            if prime_factors_dict[num][prime] > 0 and prime in prime_factors_dict:
                for other_prime in prime_factors_dict[prime]:
                    if prime_factors_dict[prime][other_prime] > 0 and other_prime in added_numbers:
                        can_add = False
                        break
                if not can_add:
                    break
        if can_add:
            added_numbers.add(num)

    # If the subset is empty, return -1
    if not added_numbers:
        return -1

    # Return the size of the subset
    return len(added_numbers)

