def min_subset_with_gcd_1(sequence):
    # Dictionary to store prime factors of each number in the sequence
    prime_factors_dict = {}

    # Get prime factors for each number in the sequence
    for num in sequence:
        prime_factors_dict[num] = prime_factors(num)

    # Check if any two numbers share common prime factors
    for i in range(len(sequence)):
