from math import gcd

def find_smallest_subset(n, nums):
    def can_be_gcd_one(nums, i):
        # Check if removing any single element makes gcd 1
        for j in range(i + 1, n):
            new_nums = nums[:i] + nums[i+1:]
            if gcd(nums[j], new_nums) == 1:
                return True
        return False

    def find_subset(nums):
        # Try to find the smallest subset with gcd 1
        for i in range(n):
            if can_be_gcd_one(nums, i):
                return [nums[i]]
        return []

    subset = find_subset(nums)
    return len(subset) if subset else -1

