def max_nodes_collected(x0, y0, ax, ay, bx, by, xs, ys, t):
    # Initialize the DP table with zeros
    dp = [[[0] * (t + 1) for _ in range(100001)] for _ in range(100001)]

    # Starting point
    dp[x0][y0][0] = 1

    # Directions: up, down, left, right
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    # Iterate over each time step
    for time in range(1, t + 1):
        for i in range(x0 - time, x0 + time + 1):
            for j in range(y0 - time, y0 + time + 1):
                if 0 <= i < 100001 and 0 <= j < 100001:
                    for dx, dy in directions:
                        ni, nj = i + dx, j + dy
                        if 0 <= ni < 100001 and 0 <= nj < 100001:
                            dp[i][j][time] = max(dp[i][j][time], dp[ni][nj][time - 1])

        # Collect data nodes at the current position
        dp[xs][ys][time] += 1

    # Find the maximum number of nodes collected within time t
    max_collected = 0
    for i in range(xs - t, xs + t + 1):
        for j in range(ys - t, ys + t + 1):
            if 0 <= i < 100001 and 0 <= j < 100001:
                max_collected = max(max_collected, dp[i][j][t])

    return max_collected

