def generate_arrays(n, k):
    queue = [[0] * n]
    visited = set()

    while queue:
        current = queue.pop(0)

        if tuple(current) in visited:
            continue

        visited.add(tuple(current))

        # Apply F
        new_f = f(current, k)
        queue.append(new_f)

        # Apply G
        for i in range(n):
            for j in range(i + 1, n):
                new_g = g(current[:i] + [j] + current[i+1:j] + [i] + current[j+1:])
                queue.append(new_g)

    return list(visited)

