def dfs(n, k, memo):
    if (n, k) in memo:
        return memo[(n, k)]

    # Check if we can form the array using F
    if k <= n:
        memo[(n, k)] = 1
        return 1

    # Check if we can form the array using G
    memo[(n, k)] = 2
    for i in range(1, k):
        memo[(n, k)] = min(memo[(n, k)], dfs(n - i, k - 1, memo))

    return memo[(n, k)]

