def generate_all_arrays(n, k):
    if n == 0:
        return [()]
    if n == 1:
        return [[i] for i in range(1, k + 1)]

    prev_arrays = generate_all_arrays(n - 1, k)
    current_arrays = []

    for arr in prev_arrays:
        for num in range(1, k + 1):
            current_arrays.append(arr + [num])

    return current_arrays

def can_be_ancestor(a, b):
    # Check if a can be generated by F or G from b
    # F(a, k) -> a repeated k times
    # G(a, x, y) -> swap x with y in a
    return a == b or any(a == F(b, k) for k in range(1, k + 1)) or any(a == G(b, x, y) for x in range(1, k + 1) for y in range(1, k + 1) if x != y)

def find_min_sequence(n, k):
    # Generate all possible arrays of size n
    all_arrays = generate_all_arrays(n, k)

    # Use a set to keep track of arrays in the sequence
    sequence = set()

    # Start with the empty array
    sequence.add(())

    # Try to add each array to the sequence
    for arr in all_arrays:
        can_add = False
        for seq_arr in sequence:
            if can_be_ancestor(seq_arr, arr):
                can_add = True
                break
        if not can_add:
            sequence.add(arr)

    # Return the size of the sequence
    return len(sequence)

