def can_reach_k(n, k, a):
    # If the sum of the list is less than k, it's impossible to reach k
    if sum(a) < k:
        return "NO"

    # Check if k is already in the list
    if k in a:
        return "YES"

    # Sort the list to find the largest element less than k
    a.sort()

    # Find the largest element less than k
    for i in range(n-1):
        if a[i] < k <= a[i+1]:
            # Check if k can be reached by subtracting the difference between k and a[i]
            if (k - a[i]) % (n - i - 1) == 0:
                return "YES"

    return "NO"

