def count_valid_substrings(S, K, L, R):
    # Initialize a dictionary to keep track of character frequencies in the current window
    freq = {}

    # Count the frequency of characters in the initial window [L, R]
    for i in range(L - 1, R):
        if S[i] in freq:
            freq[S[i]] += 1
        else:
            freq[S[i]] = 1

    # Initialize the count of valid substrings
    valid_count = 0

    # Expand the window to the right
    for i in range(R, len(S)):
        # Add the new character to the frequency counter
        if S[i] in freq:
            freq[S[i]] += 1
        else:
            freq[S[i]] = 1

        # Shrink the window from the left if any character exceeds K frequency
        while any(v > K for v in freq.values()):
            freq[S[L - 1]] -= 1
            L += 1

        # Calculate the number of valid substrings ending at index i
        valid_count += i - L + 1

    return valid_count

