def count_substrings(s, k):
    n = len(s)
    prefix_count = [[0] * (k + 1) for _ in range(n + 1)]

    for i in range(1, n + 1):
        for j in range(k + 1):
            if s[i - 1] == '0':
                prefix_count[i][j] = prefix_count[i - 1][j] + 1
            else:
