    for j in range(r + 1):
        for i in range(l - 1, -1, -1):
            zeros = j - i + 1 - prefix_count[j + 1][i]
            ones = prefix_count[j + 1][i] - prefix_count[i][i]
            if zeros <= k and ones <= k:
                total += 1
    return total

