    prefix_sum_0 = [0] * (n + 1)
    prefix_sum_1 = [0] * (n + 1)

    for i in range(n):
        if S[i] == '0':
            prefix_sum_0[i + 1] = prefix_sum_0[i] + 1
            prefix_sum_1[i + 1] = prefix_sum_1[i]
        else:
            prefix_sum_0[i + 1] = prefix_sum_0[i]
            prefix_sum_1[i + 1] = prefix_sum_1[i] + 1

    # Function to find the number of valid substrings within a range
    def count_valid_in_range(l, r):
        # Count the number of valid substrings ending at r
        valid_end = 0
        for i in range(l + 1, r + 1):
            if prefix_sum_0[i] - prefix_sum_0[l] <= K and prefix_sum_1[i] - prefix_sum_1[l] <= K:
                valid_end += 1

        # Count the number of valid substrings starting at l
        valid_start = 0
        for i in range(r - 1, l - 1, -1):
            if prefix_sum_0[i + 1] - prefix_sum_0[l] <= K and prefix_sum_1[i + 1] - prefix_sum_1[l] <= K:
                valid_start += 1

        # Adjust for double counting substrings
        double_counted = 0
        for i in range(l + 1, r):
            if prefix_sum_0[i + 1] - prefix_sum_0[l] <= K and prefix_sum_1[i + 1] - prefix_sum_1[l] <= K:
                double_counted += 1

        return valid_end + valid_start - double_counted

