def factorial(n):
    result = 1
    for i in range(2, n + 1):
        result = (result * i) % (10**9 + 7)
    return result

def binomial_coefficient(n, k):
    if k > n:
        return 0
    k = min(k, n - k)
    num = factorial(n)
    den = factorial(k) * factorial(n - k)
    return num // den

def catalan_number(k):
    return binomial_coefficient(2 * k, k) // (k + 1)

