from functools import lru_cache

def count_ways(k, balls):
    MOD = 10**9 + 7

    @lru_cache(None)
    def dp(i, j):
        if i == 1:
            return 1
        if j == 0:
            return 0
        res = 0
        for x in range(1, j):
            res += dp(i-1, x)
            res %= MOD
        return res

    total_ways = 0
    for j in range(1, balls[k-1] + 1):
        total_ways += dp(k, j)
        total_ways %= MOD

    return total_ways

