def combinations(n, k):
    return factorial(n) // (factorial(k) * factorial(n - k))

def count_ways(k, balls):
    mod = 1_000_000_007
    result = 1

    for i in range(1, k):
        result *= combinations(balls[i-1], balls[i])
        result %= mod

    return result

