def can_win(x1, y1, x2, y2, n, visited):
    # Base case: if one player has visited more than half the cells
    if (visited[x1][y1] + visited[x2][y2]) > (n // 2 + 1):
        return True

    # Get all possible moves for the current player
    moves = []
    if x1 == 1 and x2 == 1:
        if y1 > 1 and (y1 - 1, y1) not in visited:
            moves.append((y1 - 1, y1))
        if y2 > 1 and (y2 - 1, y2) not in visited:
            moves.append((y2 - 1, y2))
        if y1 < n and (y1 + 1, y1) not in visited:
            moves.append((y1 + 1, y1))
        if y2 < n and (y2 + 1, y2) not in visited:
            moves.append((y2 + 1, y2))
    elif x1 == 1 and x2 == 2:
        if y1 > 1 and (y1 - 1, y1) not in visited:
            moves.append((y1 - 1, y1))
        if y2 > 1 and (y2 - 1, y2) not in visited:
            moves.append((y2 - 1, y2))
        if y1 < n and (y1 + 1, y1) not in visited:
            moves.append((y1 + 1, y1))
        if y2 < n and (y2 + 1, y2) not in visited:
            moves.append((y2 + 1, y2))
    elif x1 == 2 and x2 == 1:
        if y1 > 1 and (y1 - 1, y1) not in visited:
            moves.append((y1 - 1, y1))
        if y2 > 1 and (y2 - 1, y2) not in visited:
            moves.append((y2 - 1, y2))
        if y1 < n and (y1 + 1, y1) not in visited:
            moves.append((y1 + 1, y1))
        if y2 < n and (y2 + 1, y2) not in visited:
            moves.append((y2 + 1, y2))
    elif x1 == 2 and x2 == 2:
        if y1 > 1 and (y1 - 1, y1) not in visited:
            moves.append((y1 - 1, y1))
        if y2 > 1 and (y2 - 1, y2) not in visited:
            moves.append((y2 - 1, y2))
        if y1 < n and (y1 + 1, y1) not in visited:
            moves.append((y1 + 1, y1))
        if y2 < n and (y2 + 1, y2) not in visited:
            moves.append((y2 + 1, y2))

    # Try each move
    for move in moves:
        new_visited = visited.copy()
        new_visited[move[0]][move[1]] = True
        if not can_win(y1, x1, move[0], move[1], n, new_visited):
