def construct_sequence(n, m, forbidden_prefix_products):
    if n == 0:
        # If there are no forbidden prefix products, we can start with 0
        return [0] * m

    # Generate all possible sequences of length m
    for i in range(1, m):
        for j in range(i + 1, m):
            for k in range(j + 1, m):
                for l in range(k + 1, m):
                    for r in range(l + 1, m):
                        sequence = [i, j, k, l, r]
                        valid = True
                        for product in forbidden_prefix_products:
                            if sum(sequence[:product + 1]) % m == product:
                                valid = False
                                break
                        if valid:
                            return sequence

    # If no valid sequence is found, this should not happen for the given constraints
    raise ValueError("No valid sequence found")

