def f(l, r):
    n = len(r)
    result = 0

    for i in range(n):
        # Count the number of 1s in the range [l, r] for the current bit position
        count_ones = 0
        for j in range(i, n):
            if r[j] == '1':
                count_ones += 1

        # If the count of 1s is odd, add the bit to the result
        if count_ones % 2 == 1:
            result |= (1 << i)

    return bin(result)[2:].zfill(n)

