def is_fibonacci(n):
    a, b = 0, 1
    while a < n:
        a, b = b, a + b
    return a == n

def is_fib_tree(n, edges):
    # Check if n is a Fibonacci number
    if not is_fibonacci(n):
        return "NO"

    # Create an adjacency list representation of the tree
    adj_list = [[] for _ in range(n)]
    for u, v in edges:
        adj_list[u - 1].append(v - 1)
        adj_list[v - 1].append(u - 1)

    # Helper function to perform DFS and check if a subtree is a Fib-tree
    def dfs(node, parent):
        size = 1
        for neighbor in adj_list[node]:
            if neighbor != parent:
                size += dfs(neighbor, node)
        if size == n or is_fibonacci(size):
            return True
        return False

    # Check if the entire tree is a Fib-tree
    return dfs(0, -1)

