from collections import defaultdict

def is_fib_tree(n, edges):
    # Create adjacency list representation of the tree
    adj_list = defaultdict(list)
    for u, v in edges:
        adj_list[u].append(v)
        adj_list[v].append(u)

    # Function to perform DFS and check if the subtree is a Fib-tree
    def dfs(node, parent, depth):
        if depth == 0:
            return True

        # Check if the current node is a leaf
        if len(adj_list[node]) == 1 and adj_list[node][0] == parent:
            return True

        # Recursively check subtrees
        for child in adj_list[node]:
            if child != parent:
                if not dfs(child, node, depth - 1):
                    return False

        # Calculate the total number of vertices in the subtree
        subtree_size = len(adj_list[node]) - 1

        # Check if the subtree size is a Fibonacci number
        k = 0
        while fib(k) <= subtree_size:
            if fib(k) == subtree_size:
                return True
            k += 1

        return False

    # Check if the entire tree is a Fib-tree
    return dfs(1, None, n - 1)

def fib(n):
    a, b = 0, 1
    for _ in range(n):
        a, b = b, a + b
    return a

