from collections import defaultdict

def is_fib_tree(n, edges):
    # Initialize adjacency list
    adj_list = defaultdict(list)
    for u, v in edges:
        adj_list[u].append(v)
        adj_list[v].append(u)

    def dfs(node, parent):
        nonlocal has_one_vertex, has_split_fib_tree
        has_one_vertex |= node == 1

        if len(adj_list[node]) <= 2:
            return True

        child_sizes = []
        for child in adj_list[node]:
            if child != parent:
                child_sizes.append(dfs(child, node))

        if len(child_sizes) == 2 and all(child_size <= 2 for child_size in child_sizes):
            has_split_fib_tree = True
            return True

        if len(child_sizes) > 2:
            return False

        return all(size <= 2 for size in child_sizes)

    has_one_vertex = False
    has_split_fib_tree = False
    dfs(1, -1)

    return has_one_vertex or has_split_fib_tree

