def check_exercise_info(N, A, S):
    # Count the number of positive and negative values in A
    positive_count = sum(1 for x in A if x >= 0)

    # Check if the number of positive values is odd
    if positive_count % 2 != 0:
        return "NO"

    # If all values are known, check if S is consistent
    if positive_count == N:
        if S == '>=>>':
            return "YES"
        else:
            return "NO"

    # Try to find a valid exercise schedule
    def backtrack(index, current_sum, last_exercise):
        if index == N - 1:
            if current_sum > last_exercise:
                return True
            return False

        if S[index] == '>':
            if current_sum <= last_exercise:
                return False
            return backtrack(index + 1, current_sum + 1, current_sum + 1)

        if S[index] == '=':
            if current_sum != last_exercise:
                return False
            return backtrack(index + 1, current_sum + 1, current_sum)

        if S[index] == '<':
            if current_sum >= last_exercise:
                return False
            return backtrack(index + 1, current_sum + 1, last_exercise + 1)

    # Start the backtracking process
    return "YES" if backtrack(0, 0, -1) else "NO"

