from itertools import combinations

def is_clique(graph, vertices):
    """Check if a subset of vertices forms a clique."""
    return all(graph[u][v] == 1 for u, v in combinations(vertices, 2))

def is_independent_set(graph, vertices):
    """Check if a subset of vertices forms an independent set."""
    return all(graph[u][v] == 0 for u, v in combinations(vertices, 2))

def find_three_acquaintances_or_unacquaintances(graph):
    """Check if there are either three pairwise acquainted or three pairwise unacquainted people."""
    for vertices in combinations(range(1, 6), 3):
        if is_clique(graph, vertices) or is_independent_set(graph, vertices):
            return True
    return False

