def chinese_remainder_theorem(a, b, mod):
    """Solve a system of congruences using the Chinese Remainder Theorem."""
    def extended_gcd(a, b):
        if b == 0:
            return a, 1, 0
        g, x1, y1 = extended_gcd(b, a % b)
        x = y1
        y = x1 - (a // b) * y1
        return g, x, y

    M = mod[0]
    for m in mod[1:]:
        g, x, y = extended_gcd(M, m)
        if g != 1:
            return None  # No solution if GCD is not 1
        M *= m // g
        x = (x * m // g) % M
    return x % M

