    directions = [(1, 0), (-1, 0), (0, 1), (0, -1)]

    # Set to store visited points
    visited = {(0, 0)}

    # Queue for BFS
    queue = [(0, 0)]

    while queue:
        x, y = queue.pop(0)

        # Check all four possible moves
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx <= n and 0 <= ny <= m:
