    # Dictionary to store LCS lengths for each pair of permutations
    lcs_lengths = defaultdict(int)

    # Compute LCS for each pair of permutations
    for i in range(m):
        for j in range(i + 1, m):
            lcs_length = longest_common_subsequence(permutations[i], permutations[j])
            lcs_lengths[(i, j)] = lcs_length
            lcs_lengths[(j, i)] = lcs_length

    # Count valid subsequences for each LCS length
    for lcs_length in lcs_lengths.values():
        if lcs_length > 1:
            count = count_valid_subsequences(permutations[0], lcs_length)
            total_ways += count

    return total_ways

