from collections import defaultdict

def lcp(x, y):
    """Longest Common Prefix between two strings x and y."""
    i = 0
    while i < len(x) and i < len(y) and x[i] == y[i]:
        i += 1
    return i

def build_trie(permutations):
    """Build a trie from a list of permutations."""
    trie = defaultdict(list)
    for perm in permutations:
        node = trie
        for char in perm:
            if char not in node:
                node[char] = defaultdict(list)
            node = node[char]
        node['end'] = True
    return trie

def count_common_subarrays(trie, permutations):
    """Count the number of valid common subarrays."""
    def dfs(node, path):
        if 'end' in node:
            common_subarrays.add(path)
        for char, next_node in node.items():
            dfs(next_node, path + char)

    common_subarrays = set()
    dfs(trie, '')
    return len(common_subarrays) - 1  # Subtract 1 to exclude the empty string

