def sum_of_f(S):
    N = len(S)
    MOD = 998244353

    # Initialize DP table
    dp = [[0] * (N + 1) for _ in range(N + 1)]

    # Base case
    dp[0][0] = 1

    # Fill the DP table
    for i in range(1, N + 1):
        for j in range(1, N + 1):
            if S[i - 1] >= dp[i - 1][0]:
                dp[i][j] = dp[i - 1][j]
            else:
                dp[i][j] = dp[i - 1][0]

    # Calculate the sum of f(S) over all subsequences
    total_sum = 0
    for i in range(1, N + 1):
        for j in range(1, N + 1):
            total_sum = (total_sum + dp[i][j]) % MOD

    return total_sum

