def count_balanced_strings(s):
    mod = 10**9 + 7
    n = len(s)

    # Count the number of '4's and '7's in the string
    count_4 = s.count('4')
    count_7 = s.count('7')

    # Initialize DP table with zeros
    dp = [[0] * (count_7 + 1) for _ in range(count_4 + 1)]

    # Base case: There's one way to have 0 '4's and 0 '7's
    dp[0][0] = 1

    # Fill the DP table
    for char in s:
        if char == '4':
            new_dp = [[0] * (count_7 + 1) for _ in range(count_4 + 1)]
            for i in range(count_4 + 1):
                for j in range(count_7 + 1):
                    if i > 0:
                        new_dp[i][j] += dp[i - 1][j]
                    if j > 0:
                        new_dp[i][j] += dp[i][j - 1]
            dp = new_dp
        else:  # char == '7'
            new_dp = [[0] * (count_7 + 1) for _ in range(count_4 + 1)]
            for i in range(count_4 + 1):
                for j in range(count_7 + 1):
                    if i < count_4:
                        new_dp[i][j] += dp[i + 1][j]
                    if j < count_7:
                        new_dp[i][j] += dp[i][j + 1]
            dp = new_dp

    # Sum up all valid states where the number of '4's equals the number of '7's
    result = sum(dp[i][i] for i in range(count_4 + 1)) % mod
    return result

