import sys

def min_operations_to_move_to_same_position(n, k, points):
    # Function to calculate Manhattan distance between two points
    def manhattan_distance(p1, p2):
        return abs(p1[0] - p2[0]) + abs(p1[1] - p2[1])

    # Check if all points can be moved to a single position
    # This is possible if the maximum distance between any two points is less than or equal to k
    max_distance = float('-inf')
    for i in range(n):
        for j in range(i + 1, n):
            dist = manhattan_distance(points[i], points[j])
            if dist > max_distance:
                max_distance = dist

    if max_distance > k:
        return -1

    # Since all points are distinct and the maximum distance is within k,
    # we can move them all to a single position by charging the ball in the center
    # of the bounding box defined by the points.
    min_ops = 0
    for point in points:
        min_ops += manhattan_distance((0, 0), point)

    return min_ops // 2

