def find_centroid(points):
    x_sum = 0
    y_sum = 0
    n = len(points)

    for x, y in points:
        x_sum += x
        y_sum += y

    centroid_x = x_sum // n
    centroid_y = y_sum // n

    return (centroid_x, centroid_y)

def min_operations_to_charge(points, k):
