def can_reach(p, q):
    # Initialize a DP table where dp[i][j] is True if it's possible to reach (i, j)
    dp = [[False] * (q + 1) for _ in range(p + 1)]

    # Base case: starting point (0, 0) is reachable
    dp[0][0] = True

    # Fill the DP table
    for i in range(p + 1):
        for j in range(q + 1):
            if dp[i][j]:
                # Alice can move to (i-1, j) or (i, j-1)
                if i > 0:
                    dp[i-1][j] = True
                if j > 0:
                    dp[i][j-1] = True
                # Alice can move to (i-k, j-k) with k = min(i-p, j-q) and 0 < k <= min(i-p, j-q)
                for k in range(1, min(i, j) + 1):
                    dp[i-k][j-k] = True

    return dp[p][q]

