import sys

def is_winning_position(m, n, p, q):
    # Base cases
    if m <= p and n <= q:
        return False  # If Alice can reach (p, q) on her first move, she wins
    if p == 0 or q == 0:
        return True   # If Alice can force Bob into a losing position, she wins

    # Check all possible moves for Alice
    for dx in range(1, m - p):
        for dy in range(1, n - q):
            if not is_winning_position(m - dx, n - dy, p, q):
                return True  # Alice can force Bob into a losing position

    # Check all possible moves for Alice with a step
    for a in range(1, min(m - p, n - q)):
        if not is_winning_position(m - a, n - a, p, q):
            return True  # Alice can force Bob into a losing position

    return False  # If no move leads to a win for Alice, Bob wins

