def dp(m, n, p, q):
    # Initialize DP table with False
    dp_table = [[False] * (n + 1) for _ in range(m + 1)]

    # Base case: the game ends when the vehicle reaches (p, q)
    dp_table[p][q] = False

    # Fill the DP table
    for i in range(m, -1, -1):
        for j in range(n, -1, -1):
            # Check all possible moves for Alice
            for a in range(1, min(i - p, j - q) + 1):
                if dp_table[i - a][j - a]:
                    dp_table[i][j] = True
                    break
            # Check all possible moves for Bob
            for a in range(1, min(i - p, j - q) + 1):
                if not dp_table[i - a][j - a]:
                    dp_table[i][j] = True
                    break

    return dp_table[0][0]

