def dp_game(m, n, p, q):
    # Initialize DP table
    dp = [[[False, False] for _ in range(n+1)] for _ in range(m+1)]

    # Base case: if the vehicle is at (p, q), the current player wins
    dp[p][q][True] = True
    dp[p][q][False] = False

    # Fill the DP table
    for x in range(m, -1, -1):
        for y in range(n, -1, -1):
            if dp[x][y][True]:  # Alice's turn
                for dx in [-1, 0]:
                    for dy in [-1, 0]:
                        if can_move(x + dx, y + dy, p, q):
                            dp[x + dx][y + dy][False] = True
                for a in range(1, min(p - x, q - y) + 1):
                    dp[x - a][y - a][False] = True
            elif dp[x][y][False]:  # Bob's turn
                for dx in [-1, 0]:
                    for dy in [-1, 0]:
                        if can_move(x + dx, y + dy, p, q):
                            dp[x + dx][y + dy][True] = True
                for a in range(1, min(p - x, q - y) + 1):
                    dp[x - a][y - a][True] = True

    # Determine the winner
    return "Alice" if dp[0][0][True] else "Bob"

