from functools import lru_cache

def can_win(m, n, p, q):
    @lru_cache(None)
    def dp(x, y):
        if x == p and y == q:
            return False
        if x >= p and y >= q:
            return True
        if x < p:
            if dp(x+1, y) or dp(x+1, y-1):
                return True
        if y < q:
            if dp(x, y+1) or dp(x-1, y+1):
                return True
        if x > p:
            if dp(x-1, y) or dp(x-1, y-1):
                return True
        if y > q:
            if dp(x, y-1) or dp(x+1, y-1):
                return True
        return False

    return dp(m, n)

