class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        root_x = self.find(x)
        root_y = self.find(y)
        if root_x == root_y:
            return
        if self.rank[root_x] > self.rank[root_y]:
            self.parent[root_y] = root_x
        elif self.rank[root_x] < self.rank[root_y]:
            self.parent[root_x] = root_y
        else:
            self.parent[root_y] = root_x
            self.rank[root_x] += 1

def count_connected_components(n, m, a):
    uf = UnionFind(2 ** n)

    # Iterate over all pairs of integers
    for i in range(m):
        for j in range(i + 1, m):
            if (a[i] & a[j]) == 0:
                uf.union(a[i], a[j])

    # Count the number of unique components
    return len({uf.find(i) for i in range(2 ** n)})

