import sys
from collections import defaultdict

def count_connected_components(n, m, arr):
    # Create a dictionary to store the adjacency list for each node
    adj_list = defaultdict(list)

    # Populate the adjacency list based on the bitwise AND condition
    for i in range(m):
        for j in range(i + 1, m):
            if (arr[i] & arr[j]) == 0:
                adj_list[arr[i]].append(arr[j])
                adj_list[arr[j]].append(arr[i])

    # Perform DFS to count connected components
    visited = [False] * (1 << n)
    def dfs(node):
        visited[node] = True
        for neighbor in adj_list[node]:
            if not visited[neighbor]:
                dfs(neighbor)

    connected_components = 0
    for node in range(1 << n):
        if not visited[node]:
            dfs(node)
            connected_components += 1

    return connected_components

