from collections import defaultdict

def count_connected_components(n, m, a):
    # Create an adjacency list for the graph
    adj_list = defaultdict(list)

    # Build the adjacency list based on the bitwise AND condition
    for i in range(m):
        for j in range(i + 1, m):
            if a[i] & a[j] == 0:
                adj_list[a[i]].append(a[j])
                adj_list[a[j]].append(a[i])

    # Initialize visited array to keep track of visited nodes
    visited = [False] * (1 << n)

    def dfs(node):
        visited[node] = True
        for neighbor in adj_list[node]:
            if not visited[neighbor]:
                dfs(neighbor)

    # Count the number of connected components
    component_count = 0
    for i in range(1 << n):
        if not visited[i]:
            dfs(i)
            component_count += 1

    return component_count

