def count_random_pictures(n: int, m: int) -> int:
    MOD = 10**9 + 7

    # Initialize DP table
    dp = [[[0] * 2 for _ in range(m)] for _ in range(n)]

    # Base case: single cell
    for i in range(n):
        for j in range(m):
            dp[i][j][0] = 1  # Black cell
            dp[i][j][1] = 1  # White cell

    # Fill DP table
    for i in range(1, n):
        for j in range(m):
            # If the current cell is black
            if dp[i-1][j][1] == 0:
                dp[i][j][0] = dp[i-1][j][0] * 2 % MOD
            else:
                dp[i][j][0] = dp[i-1][j][0] * 2 % MOD - dp[i-1][j-1][0] % MOD

            # If the current cell is white
            if dp[i-1][j][0] == 0:
                dp[i][j][1] = dp[i-1][j][1] * 2 % MOD
            else:
                dp[i][j][1] = dp[i-1][j][1] * 2 % MOD - dp[i-1][j-1][1] % MOD

    # Sum up all possible configurations
    total = 0
    for i in range(n):
        for j in range(m):
            total += dp[i][j][0] + dp[i][j][1]
            total %= MOD

    return total

