def count_regular_sequences(n, s):
    MOD = 10**9 + 7

    # Initialize dp array
    dp = [[0] * (n + 1) for _ in range(n + 1)]

    # Base case: dp[0][0] = 1 (empty sequence)
    dp[0][0] = 1

    # Fill the dp table
    for i in range(1, n + 1):
        for j in range(i + 1):
            if j > 0:
                dp[i][j] += dp[i - 1][j - 1]  # Add sequences ending with '()'
            if j < i:
                dp[i][j] += dp[i - 1][j]     # Add sequences ending with '()'
            dp[i][j] %= MOD

    # Count subsequences containing s
    def count_subsequences(s, seq):
        count = 0
        left = 0
        for right in range(len(seq)):
            if seq[right] == '(':
                left += 1
            else:
                left -= 1
            if left >= 0 and seq[left:right+1] == s:
                count += 1
        return count

    total_count = 0
    for j in range(n + 1):
        for k in range(j + 1):
            if dp[n][j] > 0:
                total_count += count_subsequences(s, dp[n][j])
                total_count %= MOD

    return total_count

