def count_valid_sequences(n, s):
    MOD = 10**9 + 7
    len_s = len(s)

    # Initialize dp array
    dp = [[[0] * (2 * n + 1) for _ in range(2 * n + 1)] for _ in range(2 * n + 1)]
    dp[0][0][0] = 1  # Base case: empty sequence

    # Fill the dp table
    for i in range(2 * n):
        for j in range(2 * n + 1):
            for k in range(2 * n + 1):
                if i + 1 < 2 * n:
                    dp[i + 1][j][k] += dp[i][j][k]
                    dp[i + 1][j][k] %= MOD
                if j > 0 and i + 1 < 2 * n:
                    dp[i + 1][j - 1][k + 1] += dp[i][j][k]
                    dp[i + 1][j - 1][k + 1] %= MOD

    # Count sequences containing s
    count = 0
    for start in range(len_s):
        for end in range(start, len_s):
            # Ensure s is within the bounds of the sequence
            if start + len_s <= 2 * n:
                # Check if the sequence before and after s is valid
                valid_before = True
                valid_after = True
                for x in range(start):
                    valid_before = valid_before and dp[x][x][x]
                for x in range(end + 1, len_s):
                    valid_after = valid_after and dp[x][x][x]

                if valid_before and valid_after:
                    count += dp[end + 1 - len_s][len_s - 1][len_s - 1]
                    count %= MOD

    return count

