def generate_all_sequences(n):
    def backtrack(seq, open_count, close_count):
        if len(seq) == 2 * n:
            yield seq
            return
        if open_count < n:
            yield from backtrack(seq + '(', open_count + 1, close_count)
        if close_count < open_count:
            yield from backtrack(seq + ')', open_count, close_count + 1)

    return list(backtrack('', 0, 0))

