from math import gcd
from typing import List

def build_tree(arr: List[int], tree: List[int], start: int, end: int, node: int):
    if start == end:
        tree[node] = arr[start]
        return
    mid = (start + end) // 2
    build_tree(arr, tree, start, mid, 2 * node)
    build_tree(arr, tree, mid + 1, end, 2 * node + 1)
    tree[node] = gcd(tree[2 * node], tree[2 * node + 1])

def query_tree(tree: List[int], start: int, end: int, node: int, left: int, right: int) -> int:
    if left > end or right < start:
        return 0
    if left <= start and end <= right:
        return tree[node]
    mid = (start + end) // 2
    return gcd(query_tree(tree, start, mid, 2 * node, left, right),
               query_tree(tree, mid + 1, end, 2 * node + 1, left, right))

def update_tree(arr: List[int], tree: List[int], start: int, end: int, node: int, index: int, value: int):
    if start == end:
        arr[index] = value
        tree[node] = value
        return
    mid = (start + end) // 2
    if index <= mid:
        update_tree(arr, tree, start, mid, 2 * node, index, value)
    else:
        update_tree(arr, tree, mid + 1, end, 2 * node + 1, index, value)
    tree[node] = gcd(tree[2 * node], tree[2 * node + 1])

def compute_sum(tree: List[int], start: int, end: int, node: int, left: int, right: int) -> int:
    if left > end or right < start:
        return 0
    if left <= start and end <= right:
        return sum(gcd(i, arr[start:end+1]) for i in range(1, end - start + 2))
    mid = (start + end) // 2
    return compute_sum(tree, start, mid, 2 * node, left, right) + compute_sum(tree, mid + 1, end, 2 * node + 1, left, right)

