import math

def dot_product(A, B):
    return A[0] * B[0] + A[1] * B[1]

def magnitude(A):
    return math.sqrt(A[0]**2 + A[1]**2)

def angle_between_vectors(A, B):
    dot = dot_product(A, B)
    mag_A = magnitude(A)
    mag_B = magnitude(B)
    if mag_A == 0 or mag_B == 0:
        return 0
    cos_theta = dot / (mag_A * mag_B)
    return math.acos(cos_theta)

def is_nice(perm, points):
    n = len(perm)
    for i in range(n - 2):
        A = points[perm[i]]
        B = points[perm[i + 1]]
        C = points[perm[i + 2]]
        BA = (B[0] - A[0], B[1] - A[1])
        BC = (C[0] - B[0], C[1] - B[1])
        angle = angle_between_vectors(BA, BC)
        if angle >= math.pi / 2:
            return False
    return True

def find_nice_permutation(points):
    n = len(points)
    for perm in itertools.permutations(range(1, n + 1)):
        if is_nice(perm, points):
            return perm
    return -1

