import math

def calculate_angle(p1, p2):
    x1, y1 = p1
    x2, y2 = p2
    dot_product = x1 * x2 + y1 * y2
    magnitude1 = math.sqrt(x1**2 + y1**2)
    magnitude2 = math.sqrt(x2**2 + y2**2)
    cos_theta = dot_product / (magnitude1 * magnitude2)
    theta = math.acos(cos_theta)
    return math.degrees(theta)

def is_nice(beatmap):
    n = len(beatmap)
    for i in range(n - 2):
        angle = calculate_angle(beatmap[i], beatmap[i + 1])
        next_angle = calculate_angle(beatmap[i + 1], beatmap[i + 2])
        if angle >= 90 or next_angle >= 90:
            return False
    return True

def find_permutation(points):
    n = len(points)
    used = [False] * n

    def backtrack(path):
        if len(path) == n:
            if is_nice(path):
                return path
            return None

        for i in range(n):
            if not used[i]:
                used[i] = True
                result = backtrack(path + [points[i]])
                if result is not None:
                    return result
                used[i] = False

        return None

    result = backtrack([])
    return result if result else -1

