class PersistentSegmentTree:
    def __init__(self, n):
        self.n = n
        self.tree = [0] * (4 * n)

    def update(self, idx, val, node=0, l=0, r=n-1):
        if l == r:
            self.tree[node] = val
            return
        mid = (l + r) // 2
        if idx <= mid:
            self.update(idx, val, 2 * node + 1, l, mid)
        else:
            self.update(idx, val, 2 * node + 2, mid + 1, r)
        self.tree[node] = self.tree[2 * node + 1] + self.tree[2 * node + 2]

    def get_kth_smallest(self, node=0, l=0, r=n-1, k=0):
        if l == r:
            return l
        mid = (l + r) // 2
        left_count = self.tree[2 * node + 1]
        if k < left_count:
            return self.get_kth_smallest(2 * node + 1, l, mid, k)
        else:
            return self.get_kth_smallest(2 * node + 2, mid + 1, r, k - left_count)

