# Class to represent a node in the BST
class TreeNode:
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None
        self.size = 1  # Size of the subtree rooted at this node

# Class to represent the BST
class BinarySearchTree:
    def __init__(self):
        self.root = None

    def insert(self, val):
        if not self.root:
            self.root = TreeNode(val)
        else:
            self._insert(self.root, val)

    def _insert(self, node, val):
        if val < node.val:
            if not node.left:
                node.left = TreeNode(val)
            else:
                self._insert(node.left, val)
        else:
            if not node.right:
                node.right = TreeNode(val)
            else:
                self._insert(node.right, val)
        node.size += 1

    def get_kth_smallest(self, node, k):
        left_size = node.left.size if node.left else 0
        if k == left_size + 1:
            return node.val
        elif k <= left_size:
            return self.get_kth_smallest(node.left, k)
        else:
            return self.get_kth_smallest(node.right, k - left_size - 1)

# Main function to process the queries
def process_queries(N, Q, queries):
    bst = BinarySearchTree()
    for i in range(1, N + 1):
        bst.insert(i)

    results = []
    for query in queries:
        if query[0] == 'UNION':
            a, b = map(int, query[1:])
            set_a = bst.root
            set_b = bst.root
            while set_a.val != a:
                if set_a.val > a:
                    set_a = set_a.left
                else:
                    set_a = set_a.right
            while set_b.val != b:
                if set_b.val > b:
                    set_b = set_b.left
                else:
                    set_b = set_b.right

            if set_a == set_b:
                continue

            # Merge the sets
            if set_a.size > set_b.size:
                set_a, set_b = set_b, set_a

            # Move all elements from set_b to set_a
            while set_b.left:
                bst.remove(set_b.val)
                set_b = set_b.right
            set_b.left = set_a.left
            set_b.right = set_a.right
            set_a.left = None
            set_a.right = None
            set_a.size = set_a.size + set_b.size

            # Update the root of the tree
            if set_a.parent:
                if set_a.parent.left == set_a:
                    set_a.parent.left = set_b
                else:
                    set_a.parent.right = set_b
            else:
                bst.root = set_b

            # Update the parent of set_b
            set_b.parent = set_a

        elif query[0] == 'GET':
            a, k = map(int, query[1:])
            set_a = bst.root
            while set_a.val != a:
                if set_a.val > a:
                    set_a = set_a.left
                else:
                    set_a = set_a.right
            result = bst.get_kth_smallest(set_a, k)
            results.append(result)

    return results

