from heapq import heappush, heappop

class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.size = [1] * n
        self.rank = [0] * n

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        px, py = self.find(x), self.find(y)
        if px == py:
            return
        if self.rank[px] < self.rank[py]:
            self.parent[px] = py
        elif self.rank[py] < self.rank[px]:
            self.parent[py] = px
        else:
            self.parent[py] = px
            self.rank[px] += 1
        self.size[py] += self.size[px]

    def get_size(self, x):
        return self.size[self.find(x)]

def process_queries(n, q, queries):
    uf = UnionFind(n)
    heap = []

    for i in range(1, n + 1):
        heappush(heap, (i, i))

    results = []

    for query in queries:
        if query[0] == 'UNION':
            a, b = map(int, query[1:])
            uf.union(a, b)
            heappop(heap)
            heappush(heap, (uf.get_size(a) + 1, a))
        elif query[0] == 'GET':
            a, k = map(int, query[1:])
            k -= 1
            while k >= 0:
                num, index = heappop(heap)
                if num > k:
                    heappush(heap, (num, index))
                    break
                k -= num
            results.append(index)

    return results

