        if bit_freq[i] > n // 2:
            inversions += bit_freq[i] - (n // 2)

    # Determine the minimum value of x
    x = 0
    for i in range(32):
        if bit_freq[i] > n // 2:
            x |= (1 << i)

    return inversions, x

