def can_kill_zombies(N, C, H):
    # Create a graph where each node represents a cave and edges represent the effect of radiation
    graph = defaultdict(list)

    # Build the graph based on the radiation powers
    for i in range(1, N + 1):
        for j in range(i - C[i], i + C[i] + 1):
            if 1 <= j <= N:
                graph[i].append(j)

    # Check if we can assign each zombie to a cave such that the radiation level matches the zombie's health level
    def dfs(node, visited, zombie_to_cave):
        if len(zombie_to_cave) == N:
            return True
        for neighbor in graph[node]:
            if neighbor not in visited:
                visited.add(neighbor)
                zombie_to_cave[neighbor] = zombie_to_cave[node] + 1
                if dfs(neighbor, visited, zombie_to_cave):
                    return True
                visited.remove(neighbor)
                zombie_to_cave[neighbor] = None
        return False

    # Try to assign each zombie to a cave
    for i in range(1, N + 1):
        visited = set([i])
        zombie_to_cave = {i: 0}
        if dfs(i, visited, zombie_to_cave):
            return "YES"

    return "NO"

