from typing import List

def build_tree(n: int, s: int) -> str:
    if n < 2 or s < n:
        return "No"

    # Start with a tree where each node is its own parent
    parents = list(range(1, n + 1))

    # Calculate the initial subtree sizes
    subtree_sizes = [1] * n

    # Fill in the subtree sizes
    current_size = 1
    for i in range(n):
        if current_size >= s:
            break
        parents[i] = parents[parents[i]] if parents[i] != i else parents[i] + 1
        subtree_sizes[i] = 1 + subtree_sizes[parents[i]]
        current_size += subtree_sizes[i]

    # If the current size is less than s, it's impossible to achieve the desired sum
    if current_size < s:
        return "No"

    # Adjust the tree to minimize the branching coefficient
    for i in range(n):
        if subtree_sizes[i] == s:
            parents[i] = i
        elif subtree_sizes[i] > s:
            parents[i] = parents[i] + 1
            subtree_sizes[i] -= 1

    # Return the result and the parents array
    return "Yes\n" + " ".join(map(str, parents[1:]))

