import sys

def kruskal(graph, n):
    # Initialize parent array for Union-Find
    parent = list(range(n + 1))

    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(x, y):
        root_x = find(x)
        root_y = find(y)
        if root_x != root_y:
            parent[root_x] = root_y

    # Sort edges by weight
    edges = sorted(graph.items(), key=lambda item: item[1])
    mst_weight = 0

    for edge, weight in edges:
        u, v = edge
        if find(u) != find(v):
            union(u, v)
            mst_weight += weight

    return mst_weight

