from collections import defaultdict
import heapq
import sys

def dijkstra(graph, start):
    distances = {node: float('inf') for node in graph}
    distances[start] = 0
    pq = [(0, start)]
    while pq:
        current_distance, current_node = heapq.heappop(pq)
        if current_distance > distances[current_node]:
            continue
        for neighbor, weight in graph[current_node].items():
            distance = current_distance + weight
            if distance < distances[neighbor]:
                distances[neighbor] = distance
                heapq.heappush(pq, (distance, neighbor))
    return distances

def assign_weights(n, edges):
    # Build the graph
    graph = defaultdict(dict)
    for u, v, w in edges:
        graph[u][v] = w
        graph[v][u] = w

    # Calculate the XOR sum of all pre-assigned weights
    xor_sum = 0
    for u, v, w in edges:
        xor_sum ^= w

    # Assign weights to make the XOR sum 0
    if xor_sum == 0:
        return 0

    # Find the minimum spanning tree using Kruskal's algorithm
    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(x, y):
        root_x = find(x)
        root_y = find(y)
        if root_x != root_y:
            parent[root_y] = root_x

    edges.sort(key=lambda e: e[2])
    parent = list(range(n))
    total_weight = 0
    for u, v, w in edges:
        if find(u) != find(v):
            union(u, v)
            total_weight += w

    # Adjust the weights to make the XOR sum 0
    for u, v, w in edges:
        if find(u) == find(v) and xor_sum % 2 == w % 2:
            total_weight -= w
            xor_sum ^= w

    return total_weight

